// === Buscar Google Ads ===
// Renova access_token via refresh_token e roda 2 queries GAQL (30d + 7d) na customer Revert.
// Retorna SEMPRE 1 item com { campanhas, totals, customer_id, error? } pra Calcular Metricas usar com safeFirst().
// Em caso de falha NÃO quebra o pipeline — retorna error preenchido e cache.google_ads herda 'error'.

function env(k) { return process.env[k] || ''; }
const clientId = env('GOOGLE_ADS_CLIENT_ID');
const clientSecret = env('GOOGLE_ADS_CLIENT_SECRET');
const refreshToken = env('GOOGLE_ADS_REFRESH_TOKEN');
const devToken = env('GOOGLE_ADS_DEVELOPER_TOKEN');
const mccId = env('GOOGLE_ADS_MCC_ID');
const customerId = env('GOOGLE_ADS_CUSTOMER_ID');
const API_VERSION = 'v17';

// Curto-circuito: se qualquer env faltar -> sinaliza not_configured pra frontend
const missing = [];
if (!clientId) missing.push('GOOGLE_ADS_CLIENT_ID');
if (!clientSecret) missing.push('GOOGLE_ADS_CLIENT_SECRET');
if (!refreshToken) missing.push('GOOGLE_ADS_REFRESH_TOKEN');
if (!devToken) missing.push('GOOGLE_ADS_DEVELOPER_TOKEN');
if (!mccId) missing.push('GOOGLE_ADS_MCC_ID');
if (!customerId) missing.push('GOOGLE_ADS_CUSTOMER_ID');

if (missing.length) {
  return [{ json: { campanhas: [], totals: { spend_7d: 0, spend_30d: 0, conversions_7d: 0, conversions_30d: 0 }, customer_id: customerId || '', status: 'not_configured', missing_envs: missing } }];
}

async function refreshAccessToken() {
  const res = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://oauth2.googleapis.com/token',
    headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
    body: 'client_id=' + encodeURIComponent(clientId) + '&client_secret=' + encodeURIComponent(clientSecret) + '&refresh_token=' + encodeURIComponent(refreshToken) + '&grant_type=refresh_token',
    json: true,
    timeout: 15000,
  });
  if (!res || !res.access_token) throw new Error('OAuth response missing access_token: ' + JSON.stringify(res || {}).slice(0, 200));
  return res.access_token;
}

async function runGaql(accessToken, query) {
  const url = 'https://googleads.googleapis.com/' + API_VERSION + '/customers/' + customerId + '/googleAds:searchStream';
  const res = await this.helpers.httpRequest({
    method: 'POST',
    url: url,
    headers: {
      Authorization: 'Bearer ' + accessToken,
      'developer-token': devToken,
      'login-customer-id': mccId,
      'Content-Type': 'application/json',
    },
    body: { query: query },
    json: true,
    timeout: 20000,
  });
  // searchStream retorna ARRAY de chunks; cada chunk tem results[]
  const chunks = Array.isArray(res) ? res : [res];
  const rows = [];
  for (let i = 0; i < chunks.length; i++) {
    const r = chunks[i] && Array.isArray(chunks[i].results) ? chunks[i].results : [];
    for (let j = 0; j < r.length; j++) rows.push(r[j]);
  }
  return rows;
}

function flattenRow(r) {
  const c = r.campaign || {};
  const m = r.metrics || {};
  return {
    id: String(c.id || ''),
    name: String(c.name || ''),
    status: String(c.status || 'UNKNOWN'),
    spend: Number(m.costMicros || 0) / 1000000,
    impressions: Number(m.impressions || 0),
    clicks: Number(m.clicks || 0),
    ctr: Number(m.ctr || 0),
    conversions: Number(m.conversions || 0),
    cost_per_conversion: Number(m.costPerConversion || 0) / 1000000,
  };
}

function sumBy(arr, key) { return arr.reduce(function(s, x){ return s + (Number(x[key]) || 0); }, 0); }

const QUERY_30D = 'SELECT campaign.id, campaign.name, campaign.status, metrics.cost_micros, metrics.impressions, metrics.clicks, metrics.ctr, metrics.conversions, metrics.cost_per_conversion FROM campaign WHERE segments.date DURING LAST_30_DAYS AND campaign.status IN ("ENABLED", "PAUSED") ORDER BY metrics.cost_micros DESC LIMIT 50';
const QUERY_7D = 'SELECT campaign.id, metrics.cost_micros, metrics.conversions FROM campaign WHERE segments.date DURING LAST_7_DAYS AND campaign.status IN ("ENABLED", "PAUSED")';

try {
  const accessToken = await refreshAccessToken.call(this);
  const rows30 = await runGaql.call(this, accessToken, QUERY_30D);
  const rows7 = await runGaql.call(this, accessToken, QUERY_7D);
  const campanhas = rows30.map(flattenRow);
  // Agregação 7d por id pra usar nos totals
  const map7 = {};
  for (let i = 0; i < rows7.length; i++) {
    const id = String((rows7[i].campaign && rows7[i].campaign.id) || '');
    const m = rows7[i].metrics || {};
    if (!map7[id]) map7[id] = { spend: 0, conversions: 0 };
    map7[id].spend += Number(m.costMicros || 0) / 1000000;
    map7[id].conversions += Number(m.conversions || 0);
  }
  const totals7 = Object.values(map7).reduce(function(s, x){ return { spend: s.spend + x.spend, conversions: s.conversions + x.conversions }; }, { spend: 0, conversions: 0 });
  const out = {
    campanhas: campanhas,
    totals: {
      spend_7d: Math.round(totals7.spend * 100) / 100,
      spend_30d: Math.round(sumBy(campanhas, 'spend') * 100) / 100,
      conversions_7d: Math.round(totals7.conversions * 100) / 100,
      conversions_30d: Math.round(sumBy(campanhas, 'conversions') * 100) / 100,
    },
    customer_id: customerId,
    status: 'ok',
  };
  return [{ json: out }];
} catch (err) {
  return [{ json: {
    campanhas: [],
    totals: { spend_7d: 0, spend_30d: 0, conversions_7d: 0, conversions_30d: 0 },
    customer_id: customerId,
    status: 'error',
    error_message: String(err && err.message ? err.message : err).slice(0, 500),
  } }];
}
